const defaultStringBufferSize = 1024

// StringBufferSize controls the buffer size used for CAPIStringBuffer outputs.
var StringBufferSize = defaultStringBufferSize

// stringFromView converts CAPIStringView to Go string.
func stringFromView(view C.struct_CAPIStringView) string {
	if view.data == nil || view.len == 0 {
		return ""
	}
	return C.GoStringN(view.data, C.int(view.len))
}

// stringFromBuffer converts CAPIStringBuffer to Go string.
func stringFromBuffer(buf C.struct_CAPIStringBuffer) string {
	if buf.data == nil || buf.len == 0 {
		return ""
	}
	return C.GoStringN(buf.data, C.int(buf.len))
}

func allocStringBuffer() (C.struct_CAPIStringBuffer, func()) {
	size := StringBufferSize
	if size <= 0 {
		size = defaultStringBufferSize
	}
	data := (*C.char)(C.malloc(C.size_t(size)))
	var buf C.struct_CAPIStringBuffer
	buf.capacity = C.uint(size)
	buf.len = 0
	buf.data = data
	return buf, func() {
		if data != nil {
			C.free(unsafe.Pointer(data))
		}
	}
}

